# Base classes module - demonstrates importing and using types
from types_module import IDisplayable, Status

@abstract
class Entity(IDisplayable):
    name: str
    status: Status

    def __init__(self, name: str):
        self.name = name
        self.status = Status.INACTIVE

    def display(self) -> str:
        return f"Entity: {self.name}"

    @abstract
    def update(self) -> None: ...

class Container:
    capacity: int
    contents: list[str]

    def __init__(self, capacity: int):
        self.capacity = capacity
        self.contents = []

    @virtual
    def add_item(self, item: str) -> bool:
        if len(self.contents) < self.capacity:
            self.contents.append(item)
            return True
        return False

    def get_summary(self) -> str:
        return f"Container: {len(self.contents)}/{self.capacity}"

