# Derived classes module - demonstrates cross-module inheritance
from types_module import Point, Status
from base_module import Entity, Container

class Player(Entity):
    position: Point
    score: int

    def __init__(self, name: str, start_x: int, start_y: int):
        super().__init__(name)
        self.position = Point(start_x, start_y)
        self.score = 0
        self.status = Status.ACTIVE

    @override
    def display(self) -> str:
        return f"Player {self.name} at ({self.position.x}, {self.position.y})"

    @override
    def update(self) -> None:
        self.position.x = self.position.x + 1

    def add_score(self, points: int) -> None:
        self.score = self.score + points

class TreasureBox(Container):
    rarity: int

    def __init__(self, capacity: int, rarity: int):
        super().__init__(capacity)
        self.rarity = rarity

    @override
    def add_item(self, item: str) -> bool:
        # Treasure boxes only accept rare items (longer names)
        if len(item) >= 4:
            return super().add_item(item)
        return False

    def get_rarity_label(self) -> str:
        if self.rarity >= 10:
            return "Legendary"
        elif self.rarity >= 5:
            return "Epic"
        else:
            return "Common"
